fbm_noise.glsl:
uniform vec4 uTime;
uniform vec4 uScale;

out vec4 fragColor;

float hash(vec2 p) {
    return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
}

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    mat2 rot = mat2(cos(0.5), sin(0.5), -sin(0.5), cos(0.5));
    for (int i = 0; i < 6; i++) {
        v += a * noise(p);
        p = rot * p * 2.0 + shift;
        a *= 0.5;
    }
    return v;
}

void main() {
    vec2 uv = vUV.st;
    float t = uTime.x * 0.3;
    float scale = uScale.x;

    float f = fbm(uv * scale + t);
    float f2 = fbm(uv * scale + f + t * 0.7);

    vec3 col = mix(vec3(0.1, 0.2, 0.4), vec3(0.9, 0.6, 0.2), f2);
    col = mix(col, vec3(0.95, 0.95, 1.0), f * 0.5);

    fragColor = TDOutputSwizzle(vec4(col, 1.0));
}

voronoi.glsl:
uniform vec4 uTime;
uniform vec4 uScale;

out vec4 fragColor;

vec2 random2(vec2 p) {
    return fract(sin(vec2(dot(p, vec2(127.1, 311.7)), dot(p, vec2(269.5, 183.3)))) * 43758.5453);
}

void main() {
    vec2 uv = vUV.st;
    float t = uTime.x;
    float scale = uScale.x;

    vec2 st = uv * scale;
    vec2 i_st = floor(st);
    vec2 f_st = fract(st);

    float m_dist = 1.0;
    vec2 m_point;

    for (int y = -1; y <= 1; y++) {
        for (int x = -1; x <= 1; x++) {
            vec2 neighbor = vec2(float(x), float(y));
            vec2 point = random2(i_st + neighbor);
            point = 0.5 + 0.5 * sin(t + 6.2831 * point);
            vec2 diff = neighbor + point - f_st;
            float dist = length(diff);
            if (dist < m_dist) {
                m_dist = dist;
                m_point = point;
            }
        }
    }

    vec3 col = vec3(0.0);
    col += m_dist * 0.8;
    col.r += smoothstep(0.0, 0.05, m_dist) * m_point.x;
    col.b += smoothstep(0.0, 0.05, m_dist) * m_point.y;
    col += 1.0 - smoothstep(0.0, 0.02, m_dist);

    fragColor = TDOutputSwizzle(vec4(col, 1.0));
}

plasma.glsl:
uniform vec4 uTime;

out vec4 fragColor;

void main() {
    vec2 uv = vUV.st;
    float t = uTime.x;

    float p1 = sin(uv.x * 10.0 + t * 1.2);
    float p2 = sin(uv.y * 8.0 - t * 0.9);
    float p3 = sin((uv.x + uv.y) * 6.0 + t * 0.6);
    float p4 = sin(length(uv - 0.5) * 12.0 - t * 1.5);
    float plasma = (p1 + p2 + p3 + p4) * 0.25;

    vec3 col;
    col.r = sin(plasma * 3.14 + t * 0.3) * 0.5 + 0.5;
    col.g = sin(plasma * 3.14 + t * 0.3 + 2.094) * 0.5 + 0.5;
    col.b = sin(plasma * 3.14 + t * 0.3 + 4.188) * 0.5 + 0.5;

    fragColor = TDOutputSwizzle(vec4(col, 1.0));
}

spirograph.glsl:
uniform vec4 uTime;

out vec4 fragColor;

void main() {
    vec2 uv = vUV.st * 2.0 - 1.0;
    float t = uTime.x * 0.5;

    float d = 1e10;
    for (float i = 0.0; i < 200.0; i++) {
        float a = i * 0.03 + t;
        float r1 = 0.6, r2 = 0.25, r3 = 0.15;
        vec2 p = vec2(
            r1 * cos(a) + r2 * cos(a * 3.7) + r3 * cos(a * 7.3),
            r1 * sin(a) + r2 * sin(a * 3.7) + r3 * sin(a * 7.3)
        );
        d = min(d, length(uv - p));
    }

    vec3 col = vec3(0.0);
    col += 0.005 / (d + 0.005) * vec3(0.4, 0.7, 1.0);
    col += 0.002 / (d + 0.002) * vec3(1.0, 0.5, 0.2);

    fragColor = TDOutputSwizzle(vec4(col, 1.0));
}

bloom.glsl:
uniform vec4 uIntensity;

out vec4 fragColor;

void main() {
    vec2 uv = vUV.st;
    vec2 texel = 1.0 / uTDOutputInfo.res.zw;
    float intensity = uIntensity.x;

    vec4 sum = vec4(0.0);
    float weights[5] = float[](0.227, 0.194, 0.121, 0.054, 0.016);

    // Two-pass approximation in single pass
    for (int i = -4; i <= 4; i++) {
        for (int j = -4; j <= 4; j++) {
            vec2 offset = vec2(float(i), float(j)) * texel * 2.0;
            float w = weights[abs(i)] * weights[abs(j)];
            sum += texture(sTD2DInputs[0], uv + offset) * w;
        }
    }

    vec4 original = texture(sTD2DInputs[0], uv);
    vec4 bloom = max(sum - 0.3, 0.0) * intensity;

    fragColor = TDOutputSwizzle(original + bloom);
}

chromatic_aberration.glsl:
uniform vec4 uAmount;

out vec4 fragColor;

void main() {
    vec2 uv = vUV.st;
    vec2 center = uv - 0.5;
    float amount = uAmount.x;

    vec2 offsetR = center * amount * 0.01;
    vec2 offsetB = center * amount * -0.01;

    float r = texture(sTD2DInputs[0], uv + offsetR).r;
    float g = texture(sTD2DInputs[0], uv).g;
    float b = texture(sTD2DInputs[0], uv + offsetB).b;
    float a = texture(sTD2DInputs[0], uv).a;

    fragColor = TDOutputSwizzle(vec4(r, g, b, a));
}

edge_detect.glsl:
uniform vec4 uThreshold;

out vec4 fragColor;

void main() {
    vec2 uv = vUV.st;
    vec2 texel = 1.0 / uTDOutputInfo.res.zw;

    // Sobel kernels
    float tl = length(texture(sTD2DInputs[0], uv + vec2(-texel.x, texel.y)).rgb);
    float t  = length(texture(sTD2DInputs[0], uv + vec2(0.0, texel.y)).rgb);
    float tr = length(texture(sTD2DInputs[0], uv + vec2(texel.x, texel.y)).rgb);
    float l  = length(texture(sTD2DInputs[0], uv + vec2(-texel.x, 0.0)).rgb);
    float r  = length(texture(sTD2DInputs[0], uv + vec2(texel.x, 0.0)).rgb);
    float bl = length(texture(sTD2DInputs[0], uv + vec2(-texel.x, -texel.y)).rgb);
    float b  = length(texture(sTD2DInputs[0], uv + vec2(0.0, -texel.y)).rgb);
    float br = length(texture(sTD2DInputs[0], uv + vec2(texel.x, -texel.y)).rgb);

    float gx = tl + 2.0*l + bl - tr - 2.0*r - br;
    float gy = tl + 2.0*t + tr - bl - 2.0*b - br;
    float edge = sqrt(gx*gx + gy*gy);

    float threshold = uThreshold.x;
    edge = smoothstep(threshold, threshold + 0.1, edge);

    fragColor = TDOutputSwizzle(vec4(vec3(edge), 1.0));
}

uv_debug.glsl:
uniform vec4 uGridSize;

out vec4 fragColor;

void main() {
    vec2 uv = vUV.st;
    float grid = uGridSize.x;

    vec3 col = vec3(uv.x, uv.y, 0.0);

    // Grid lines
    vec2 gridUV = fract(uv * grid);
    float line = step(0.97, gridUV.x) + step(0.97, gridUV.y);
    col = mix(col, vec3(1.0), line * 0.5);

    // Center crosshair
    float cross = step(abs(uv.x - 0.5), 0.002) + step(abs(uv.y - 0.5), 0.002);
    col = mix(col, vec3(1.0, 1.0, 0.0), cross * 0.8);

    fragColor = TDOutputSwizzle(vec4(col, 1.0));
}

checkerboard.glsl:
uniform vec4 uTime;
uniform vec4 uScale;

out vec4 fragColor;

void main() {
    vec2 uv = vUV.st;
    float t = uTime.x;
    float scale = uScale.x;

    vec2 grid = floor(uv * scale + t * 0.2);
    float check = mod(grid.x + grid.y, 2.0);

    vec3 col1 = vec3(0.15);
    vec3 col2 = vec3(0.85);
    vec3 col = mix(col1, col2, check);

    fragColor = TDOutputSwizzle(vec4(col, 1.0));
}

basic_sdf.glsl:
uniform vec4 uTime;

out vec4 fragColor;

float sdSphere(vec3 p, float r) { return length(p) - r; }
float sdPlane(vec3 p) { return p.y + 1.0; }

float scene(vec3 p) {
    float t = uTime.x;
    vec3 sp = p - vec3(0.0, sin(t) * 0.3, 0.0);
    float sphere = sdSphere(sp, 0.8);
    float plane = sdPlane(p);
    return min(sphere, plane);
}

vec3 calcNormal(vec3 p) {
    vec2 e = vec2(0.001, 0.0);
    return normalize(vec3(
        scene(p + e.xyy) - scene(p - e.xyy),
        scene(p + e.yxy) - scene(p - e.yxy),
        scene(p + e.yyx) - scene(p - e.yyx)
    ));
}

void main() {
    vec2 uv = vUV.st * 2.0 - 1.0;
    uv.x *= uTDOutputInfo.res.z / uTDOutputInfo.res.w;

    vec3 ro = vec3(0.0, 0.5, 3.0);
    vec3 rd = normalize(vec3(uv, -1.5));

    float t = 0.0;
    for (int i = 0; i < 80; i++) {
        vec3 p = ro + rd * t;
        float d = scene(p);
        if (d < 0.001 || t > 20.0) break;
        t += d;
    }

    vec3 col = vec3(0.05, 0.05, 0.1);
    if (t < 20.0) {
        vec3 p = ro + rd * t;
        vec3 n = calcNormal(p);
        vec3 light = normalize(vec3(1.0, 2.0, 1.5));
        float diff = max(dot(n, light), 0.0);
        float spec = pow(max(dot(reflect(-light, n), -rd), 0.0), 32.0);
        col = vec3(0.6, 0.3, 0.2) * diff + vec3(1.0) * spec * 0.5;
        col += vec3(0.05);
    }

    col = pow(col, vec3(0.4545));
    fragColor = TDOutputSwizzle(vec4(col, 1.0));
}
